import { useState } from "react";
import { Routes, Route, Navigate, useNavigate } from "react-router-dom"; // Router більше не потрібен тут
import "./css/main.css";
import RegisterPage from "./pages/register";
import LoginPage from "./pages/login";

function App() {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const navigate = useNavigate(); // Тепер це працює!

  const goToRegister = () => navigate("/register");
  const loginUser = () => setIsAuthenticated(true);

  return (
    <div className="main">
      <Routes>
        <Route
          path="/"
          element={
            isAuthenticated ? (
              <div>Main Page</div>
            ) : (
              <Navigate to="/login" replace />
            )
          }
        />

        <Route
          path="/register"
          element={
            isAuthenticated ? (
              <Navigate to="/" replace />
            ) : (
              <RegisterPage onRegister={() => setIsAuthenticated(true)} />
            )
          }
        />

        <Route
          path="/login"
          element={
            isAuthenticated ? (
              <Navigate to="/" replace />
            ) : (
              <LoginPage
                onLogin={loginUser}
                changeOnRegisterPage={goToRegister}
              />
            )
          }
        />
      </Routes>
    </div>
  );
}

export default App;
